from z3 import *

s = Solver()

# 1. Symbolic inputs
base = Int('base')
exp = Int('exp')

# 2. Preconditions
s.add(exp >= 0)
s.add(exp <= 15) # Bounded verification to ensure decidability

# 3. Model the function logic using Z3 expressions
# We unroll the recursion for the bounded domain to build the Z3 AST
def z3_power(b, e_val):
    if e_val == 0:
        return IntVal(1)
    if e_val % 2 == 0:
        half = z3_power(b, e_val // 2)
        return half * half
    else:
        return b * z3_power(b, e_val - 1)

result = z3_power(base, 0)
for i in range(1, 16):
    result = If(exp == i, z3_power(base, i), result)

# Model the expected correct behavior (naive exponentiation)
def z3_naive_power(b, e_val):
    if e_val == 0:
        return IntVal(1)
    return b * z3_naive_power(b, e_val - 1)

expected_result = z3_naive_power(base, 0)
for i in range(1, 16):
    expected_result = If(exp == i, z3_naive_power(base, i), expected_result)

# 4. Negation of postcondition (what would make the output WRONG)
s.add(result != expected_result)

# 5. Check
if s.check() == sat:
    print("COUNTEREXAMPLE")
    m = s.model()
    for d in m.decls():
        print(f"  {d.name()} = {m[d]}")
else:
    print("VERIFIED")
